INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1000, 0, "様々なミニゲームをご用意してい\nますよ！\nどのミニゲームで遊びますか？", 1000001, 13, "2020-02-15 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1000, 0, "楽しいミニゲームをご紹介！\nあなたはどのミニゲームで\n遊びますか？", 1000002, 13, "2020-02-15 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1001, 0, "こちらは{0}ルピで\n販売中！\nぜひ購入して\n遊んでくださいね！", 1001001, 13, "2020-02-15 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1002, 0, "動くハートに合わせてタップ！\nシズルさんとエリコさんの\nチョコレートケーキ作りを\nお手伝いしましょう！", 1002001, 12, "2020-02-15 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1003, 0, "クウカさんを引っ張ってより遠く\nへ飛ばしてあげましょう！\n色々なハプニングでクウカさんに\nエクスタシーを届けましょう！", 1003001, 11, "2020-02-15 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1004, 0, "左右をタップしてマジムンを倒し\nましょう！\n放て！\n琉球犬アラウンドシュート！", 1004001, 3, "2020-02-15 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1005, 0, "パネルをタップしてドラゴンズ\nネストのみなさんと一緒に\nしりとり対決をしませんか？\nおしりに「ん」はご法度です。", 1005001, 7, "2020-02-15 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1006, 0, "素早い動きのネズミに合わせ、\nタップで撃退！\nやる気のリンさんと一緒に\n大切なチーズを守りましょう！", 1006001, 2, "2020-05-31 12:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1007, 0, "ミサトさんや部員のみなさんと\nバッティングの特訓ですよ！\nホームランを目指して、ボールを\nタイミングよく打ち返しましょう", 1007001, 4, "2020-08-15 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1008, 0, "カルミナメダルを使って、\n応援グッズをゲットしましょう！\nメダルはルピを使って\n交換できますよ。\n", 1008001, 6, "2021-08-31 12:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1009, 0, "食べたプリンはプリンノート\nで確認してみましょう！\nプリンの材料はルピを使って\n購入できますよ。", 1009001, 13, "2021-12-18 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1010, 0, "チームでクイズに挑みましょう！\nソロで自分の実力を試すか、マル\nチで仲間と一緒に遊ぶか、好きな\nモードを選んでくださいね♪", 1010001, 4, "2022-02-15 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1011, 0, "３つのラウンドを駆け抜け、\n総合１位を目指しましょう！\n参加者の皆さんの特徴や、\nＧＰの特徴にも注目です♪", 1011001, 6, "2022-07-18 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1012, 0, "キャルさん、スズナさんと一緒に\nクイズでお勉強しましょう！\n放課後の教室で二人きりって…\nなんだかドキドキしますね♪", 1012001, 6, "2023-09-18 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1013, 0, "魔物の討伐任務にいざ行軍！\nエリコさん、マコトさんの\n頼もしい背中は、\n新兵さんたちの憧れですね♪", 1013001, 6, "2024-04-18 15:00:00", "2030-04-01 14:00:00");
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (190801, 1014, 0, "バンディ・シスターズのみなさん\nと戦車バトルに挑戦です！\nパーツやメンバーの組み合わせで\nマシンの特徴が変化しますよ♪", 1014001, 6, "2024-11-18 15:00:00", "2030-04-01 14:00:00");
